+	for (k = 0; k < dim; k++) {
+	    new_stress += vectors_inner_productf(n, coords[k], b[k]);
+	}
+	new_stress *= 2;
+	new_stress += constant_term;	// only after mult by 2              
+	for (k = 0; k < dim; k++) {
+	    right_mult_with_vector_ff(lap2, n, coords[k], tmp_coords);
