+    if (coords != NULL) {
+	for (i = 0; i < dim; i++) {
+	    for (int j = 0; j < n; j++) {
+		d_coords[i][j] = coords[i][j];
+	    }
+	}
+	free(coords[0]);
+	free(coords);
+    }
+
+    free(tmp_coords);
+    free(dist_accumulator);
+    free(degrees);
+    free(lap2);
+
+    free(lap1);
+
+finish:
+    if (cMajEnv != NULL) {
+	deleteCMajEnv(cMajEnv);
+    }
+    if (b) {
+	free(b[0]);
+	free(b);
+    }
+    free(ordering);
+
+    free(levels);
+
+    return iterations;
+}
