+static int distY(box * b1, box * b2)
+{
+    return ((b1->UR.y - b1->LL.y) + (b2->UR.y - b2->LL.y)) / 2;
+}
+
+static int distX(box * b1, box * b2)
+{
+    return ((b1->UR.x - b1->LL.x) + (b2->UR.x - b2->LL.x)) / 2;
+}
