+static void closeGraph(graph_t * cg)
+{
+    node_t *n;
+    for (n = agfstnode(cg); n; n = agnxtnode(cg, n)) {
+	free_list(ND_in(n));
+	free_list(ND_out(n));
+    }
+    agclose(cg);
+}
