+/* constrainX:
+ * Create the X constrains and solve. We use a linear objective function
+ * (absolute values rather than squares), so we can reuse network simplex.
+ * The constraints are encoded as a dag with edges having a minimum length.
+ */
+static void constrainX(graph_t* g, nitem* nlist, int nnodes, intersectfn ifn,
+                       int ortho)
+{
+    Dt_t *list = dtopen(&constr, Dtobag);
+    nitem *p = nlist;
+    graph_t *cg;
+    int i;
+
+    for (i = 0; i < nnodes; i++) {
+	p->val = p->pos.x;
+	dtinsert(list, p);
+	p++;
+    }
+    if (ortho)
+	cg = mkConstraintG(list, ifn, distX);
+    else
+	cg = mkNConstraintG(g, list, ifn, distX);
+    rank(cg, 2, INT_MAX);
+
+    p = nlist;
+    for (i = 0; i < nnodes; i++) {
+	int newpos, oldpos, delta;
+	oldpos = p->pos.x;
+	newpos = ND_rank(p->cnode);
+	delta = newpos - oldpos;
+	p->pos.x = newpos;
+	p->bb.LL.x += delta;
+	p->bb.UR.x += delta;
+	p++;
+    }
+
+    closeGraph(cg);
+    dtclose(list);
+}
+
+/* constrainY:
+ * See constrainX.
+ */
+static void constrainY(graph_t* g, nitem* nlist, int nnodes, intersectfn ifn,
+                       int ortho)
+{
+    Dt_t *list = dtopen(&constr, Dtobag);
+    nitem *p = nlist;
+    graph_t *cg;
+    int i;
+
+    for (i = 0; i < nnodes; i++) {
+	p->val = p->pos.y;
+	dtinsert(list, p);
+	p++;
+    }
+    if (ortho)
+	cg = mkConstraintG(list, ifn, distY);
+    else
+	cg = mkNConstraintG(g, list, ifn, distY);
+    rank(cg, 2, INT_MAX);
+#ifdef DEBUG
+    {
+	Agsym_t *mlsym = agattr(cg, AGEDGE, "minlen", "");
+	Agsym_t *rksym = agattr(cg, AGNODE, "rank", "");
+	char buf[100];
+	node_t *n;
+	edge_t *e;
+	for (n = agfstnode(cg); n; n = agnxtnode(cg, n)) {
+	    snprintf(buf, sizeof(buf), "%d", ND_rank(n));
+	    agxset(n, rksym, buf);
+	    for (e = agfstedge(cg, n); e; e = agnxtedge(cg, e, n)) {
+		snprintf(buf, sizeof(buf), "%d", ED_minlen(e));
+		agxset(e, mlsym, buf);
+	    }
+	}
+    }
+#endif
+
+    p = nlist;
+    for (i = 0; i < nnodes; i++) {
+	int newpos, oldpos, delta;
+	oldpos = p->pos.y;
+	newpos = ND_rank(p->cnode);
+	delta = newpos - oldpos;
+	p->pos.y = newpos;
+	p->bb.LL.y += delta;
+	p->bb.UR.y += delta;
+	p++;
+    }
+
+    closeGraph(cg);
+    dtclose(list);
+}
+
+/* overlaps:
+ */
+static int overlaps(nitem * p, int cnt)
+{
+    int i, j;
+    nitem *pi = p;
+    nitem *pj;
+
+    for (i = 0; i < cnt - 1; i++) {
+	pj = pi + 1;
+	for (j = i + 1; j < cnt; j++) {
+	    if (OVERLAP(pi->bb, pj->bb))
+		return 1;
+	    pj++;
+	}
+	pi++;
+    }
+    return 0;
+}
+
+/* initItem:
+ */
+static void initItem(node_t * n, nitem * p, expand_t margin)
+{
+    int x = POINTS(SCALE * ND_pos(n)[0]);
+    int y = POINTS(SCALE * ND_pos(n)[1]);
+    int w2, h2;
+    box b;
+
+    if (margin.doAdd) {
+	w2 = SCALE * (POINTS(ND_width(n)/2.0) + margin.x);
+	h2 = SCALE * (POINTS(ND_height(n)/2.0) + margin.y);
+    }
+    else {
+	w2 = POINTS(margin.x * SCALE2 * ND_width(n));
+	h2 = POINTS(margin.y * SCALE2 * ND_height(n));
+    }
+
+    b.LL.x = x - w2;
+    b.LL.y = y - h2;
+    b.UR.x = x + w2;
+    b.UR.y = y + h2;
+
+    p->pos.x = x;
+    p->pos.y = y;
+    p->np = n;
+    p->bb = b;
+}
