+/* destroy:
+ * Destroy each edge using v, then destroy v
+ */
+static void
+destroy (GtsVertex* v)
+{
+    GSList * i;
+
+    i = v->segments;
+    while (i) {
+	GSList * next = i->next;
+	gts_object_destroy (i->data);
+	i = next;
+    }
+    g_assert (v->segments == NULL);
+    gts_object_destroy(GTS_OBJECT(v));
+}
