+static int addEdge(void *edge, void *state) {
+    GtsSegment *e = edge;
+    estate *es = state;
+
+    int source = ((GVertex*)e->v1)->idx;
+    int dest = ((GVertex*)e->v2)->idx;
+
+    es->edges[2 * es->n] = source;
+    es->edges[2 * es->n + 1] = dest;
+    es->n += 1;
+
+    return 0;
+}
