+static int vcmp(const void *x, const void *y, void *values) {
+    const int *a = x;
+    const int *b = y;
+    const double *_vals = values;
+    double va = _vals[*a];
+    double vb = _vals[*b];
+
+    if (va < vb) return -1; 
+    else if (va > vb) return 1; 
+    else return 0;
+}
