+static void remove_edge(v_data * graph, int source, int dest)
+{
+    int i;
+    for (i = 1; i < graph[source].nedges; i++) {
+	if (graph[source].edges[i] == dest) {
+	    graph[source].edges[i] = graph[source].edges[--graph[source].nedges];
+	    break;
+	}
+    }
+}
