+    b = (he->ystar - ymin) / deltay * pq->hashsize;
+    if (b < 0)
+	bucket = 0;
+    else if (b >= pq->hashsize)
+	bucket = pq->hashsize - 1;
+    else
+	bucket = b;
+    if (bucket < pq->min)
+	pq->min = bucket;
+    return bucket;
