+static void
+freeTripoly (tripoly_t* trip)
+{
+    tri* tp;
+    tri* nxt;
+
+    free (trip->poly.ps);
+    for (size_t i = 0; i < trip->poly.pn; i++) {
+	for (tp = trip->triMap[i]; tp; tp = nxt) {
+	    nxt = tp->nxttri;
+	    free (tp);
+	}
+    }
+    free (trip->triMap);
+    free (trip);
+}
