+/* resetGraph:
+ * Remove edges and nodes added for current edge routing
+ */
+static void resetGraph(tgraph *g, int ncnt, int ecnt,
+                       size_t *original_edge_count) {
+    int i;
+    tnode *np = g->nodes;
+    g->nedges = ecnt;
+    for (i = 0; i < ncnt; i++) {
+	np->ne = original_edge_count[i];
+	np++;
+    }
+}
