+    char    buf[BUFSIZ];
+
+    if (Ndim >= 3 && N_z) {
+	for (n = agfstnode(g); n; n = agnxtnode(g, n)) {
+	    snprintf(buf, sizeof(buf), "%lf", POINTS_PER_INCH * ND_pos(n)[2]);
+	    agxset(n, N_z, buf);
+	}
