+static void make_barriers(Ppoly_t **poly, int npoly, int pp, int qp,
+                          Pedge_t **barriers, size_t *n_barriers) {
+    int i, j, k;
+
+    size_t n = 0;
+    for (i = 0; i < npoly; i++) {
+	if (i == pp)
+	    continue;
+	if (i == qp)
+	    continue;
+	n += poly[i]->pn;
+    }
+    Pedge_t *bar = gv_calloc(n, sizeof(Pedge_t));
+    size_t b = 0;
+    for (i = 0; i < npoly; i++) {
+	if (i == pp)
+	    continue;
+	if (i == qp)
+	    continue;
+	for (j = 0; j < (int)poly[i]->pn; j++) {
+	    k = j + 1;
+	    if (k >= (int)poly[i]->pn)
+		k = 0;
+	    bar[b].a = poly[i]->ps[j];
+	    bar[b].b = poly[i]->ps[k];
+	    b++;
+	}
+    }
+    assert(b == n);
+    *barriers = bar;
+    *n_barriers = n;
+}
+
+static Ppoint_t genPt(double x, double y, pointf c)
+{
+    Ppoint_t p;
+
+    p.x = x + c.x;
+    p.y = y + c.y;
+    return p;
+}
+
+static Ppoint_t recPt(double x, double y, pointf c, expand_t* m)
+{
+    Ppoint_t p;
+
+    p.x = x * m->x + c.x;
+    p.y = y * m->y + c.y;
+    return p;
+}
