+typedef struct {
+    node_t *n1;
+    pointf p1;
+    node_t *n2;
+    pointf p2;
+} edgeinfo;
+typedef struct {
+    Dtlink_t link;
+    edgeinfo id;
+    edge_t *e;
+} edgeitem;
+
+static void *newitem(void *p, Dtdisc_t *disc) {
+    edgeitem *obj = p;
+    edgeitem *newp;
+
+    (void)disc;
+    newp = gv_alloc(sizeof(edgeitem));
+    newp->id = obj->id;
+    newp->e = obj->e;
+    ED_count(newp->e) = 1;
+
+    return newp;
+}
+
+static int cmpitems(void *k1, void *k2) {
+    const edgeinfo *key1 = k1;
+    const edgeinfo *key2 = k2;
+    if (key1->n1 > key2->n1)
+	return 1;
+    if (key1->n1 < key2->n1)
+	return -1;
+    if (key1->n2 > key2->n2)
+	return 1;
+    if (key1->n2 < key2->n2)
+	return -1;
+
+    if (key1->p1.x > key2->p1.x)
+	return 1;
+    if (key1->p1.x < key2->p1.x)
+	return -1;
+    if (key1->p1.y > key2->p1.y)
+	return 1;
+    if (key1->p1.y < key2->p1.y)
+	return -1;
+    if (key1->p2.x > key2->p2.x)
+	return 1;
+    if (key1->p2.x < key2->p2.x)
+	return -1;
+    if (key1->p2.y > key2->p2.y)
+	return 1;
+    if (key1->p2.y < key2->p2.y)
+	return -1;
+    return 0;
+}
+
+Dtdisc_t edgeItemDisc = {
+    offsetof(edgeitem, id),
+    sizeof(edgeinfo),
+    offsetof(edgeitem, link),
+    newitem,
+    free,
+    cmpitems,
+};
