+
+static int isBox(Point *verts, size_t cnt) {
+    if (cnt != 4)
+	return 0;
+
+    if (verts[0].y == verts[1].y)
+	return ((verts[2].y == verts[3].y) &&
+		(verts[0].x == verts[3].x) && (verts[1].x == verts[2].x));
+    else
+	return ((verts[0].x == verts[1].x) &&
+		(verts[2].x == verts[3].x) &&
+		(verts[0].y == verts[3].y) && (verts[1].y == verts[2].y));
+}
