+static Point makeScaledTransPoint(double x, double y, double dx, double dy) {
+    Point rv;
+    rv.x = PS2INCH(x) + dx;
+    rv.y = PS2INCH(y) + dy;
+    return rv;
+}
+
+static Point makeScaledPoint(double x, double y)
+{
+    Point rv;
+    rv.x = PS2INCH(x);
+    rv.y = PS2INCH(y);
+    return rv;
