+	PUTPT(verts[0], b.x, b.y);
+	PUTPT(verts[1], -b.x, b.y);
+	PUTPT(verts[2], -b.x, -b.y);
+	PUTPT(verts[3], b.x, -b.y);
+    } else
+	switch (shapeOf(n)) {
