+		        verts[i].y = poly->vertices[i].y * (1.0 + ymargin/h);
+		        verts[i].x = PS2INCH(verts[i].x);
+		        verts[i].y = PS2INCH(verts[i].y);
+		    }
+		}
+	    } else
+		verts = genRound(n, &sides, xmargin, ymargin);
