+	    verts[1] = makeScaledTransPoint(b.UR.x, b.LL.y, xmargin, -ymargin);
+	    verts[2] = makeScaledTransPoint(b.UR.x, b.UR.y, xmargin, ymargin);
+	    verts[3] = makeScaledTransPoint(b.LL.x, b.UR.y, -xmargin, ymargin);
