+	    for (j = 0; j < len; j++) {
+		if (dist_accumulator[j] >= FLT_MAX || dist_accumulator[j] < 0) {
+		    dist_accumulator[j] = 0;
+		}
+	    }
+
+	    count++;		/* save place for the main diagonal entry */
+	    degree = 0;
+	    if (exp == 2) {
+		for (j = 0; j < len; j++, count++) {
+		    val = lap1[count] *= dist_accumulator[j];
+		    degree += val;
+		    degrees[i + j + 1] -= val;
+		}
+	    } else {
+		for (j = 0; j < len; j++, count++) {
+		    val = lap1[count] = dist_accumulator[j];
+		    degree += val;
+		    degrees[i + j + 1] -= val;
+		}
+	    }
+	    degrees[i] -= degree;
+	}
