+	for (k = 0; k < dim; k++) {
+	    /* b[k] := lap1*coords[k] */
+	    right_mult_with_vector_ff(lap1, n, coords[k], b[k]);
+	}
+
+
+	/* compute new stress  */
+	/* remember that the Laplacians are negated, so we subtract instead of add and vice versa */
+	new_stress = 0;
+	for (k = 0; k < dim; k++) {
+	    new_stress += vectors_inner_productf(n, coords[k], b[k]);
+	}
+	new_stress *= 2;
