+	    fprintf(stderr, "%.3f ", new_stress);
+	    if ((iterations + 5) % 50 == 0)
+		fprintf(stderr, "\n");
+	}
+    }
+    if (Verbose) {
+	fprintf(stderr, "\nfinal e = %f %d iterations %.2f sec\n",
+		compute_stressf(coords, lap2, dim, n, exp),
+		iterations, elapsed_sec());
+    }
+
+    for (i = 0; i < dim; i++) {
+	for (j = 0; j < n; j++) {
+	    d_coords[i][j] = coords[i][j];
+	}
+    }
+finish1:
+    free(f_storage);
+    free(coords);
+
+    free(lap2);
+    if (b) {
+	free(b[0]);
+	free(b);
+    }
+    free(tmp_coords);
+    free(dist_accumulator);
+    free(degrees);
+    free(lap1);
+    return iterations;
