+static int lenattr(edge_t* e, Agsym_t* index, double* val)
+{
+    char* s;
+
+    if (index == NULL)
+	return 1;
+
+    s = agxget(e, index);
+    if (*s == '\0') return 1;
+
+    if (sscanf(s, "%lf", val) < 1 || *val < 0 || (*val == 0 && !Nop)) {
+	agwarningf("bad edge len \"%s\"", s);
+	return 2;
+    }
+    else
+	return 0;
