+    double **D = GD_dist(G);
+
+    vn = GD_neato_nlist(G)[n];
+    for (l = 0; l < Ndim; l++)
+	for (k = 0; k < Ndim; k++)
+	    Msub(l, k) = 0.0;
+    for (i = 0; i < nG; i++) {
+	if (n == i)
+	    continue;
+	vi = GD_neato_nlist(G)[i];
+	sq = 0.0;
+	for (k = 0; k < Ndim; k++) {
+	    t[k] = ND_pos(vn)[k] - ND_pos(vi)[k];
+	    sq += (t[k] * t[k]);
+	}
+	scale = 1 / fpow32(sq);
+	for (k = 0; k < Ndim; k++) {
+	    for (l = 0; l < k; l++)
+		Msub(l, k) += K[n][i] * D[n][i] * t[k] * t[l] * scale;
+	    Msub(k, k) +=
+		K[n][i] * (1.0 - D[n][i] * (sq - t[k] * t[k]) * scale);
+	}
+    }
+    for (k = 1; k < Ndim; k++)
+	for (l = 0; l < k; l++)
+	    Msub(k, l) = Msub(l, k);
+}
+
+node_t *choose_node(graph_t * G, int nG)
+{
+    int i, k;
+    double m, max;
+    node_t *choice, *np;
+    static int cnt = 0;
+
+    cnt++;
+    if (GD_move(G) >= MaxIter)
+	return NULL;
+    max = 0.0;
+    choice = NULL;
+    for (i = 0; i < nG; i++) {
+	np = GD_neato_nlist(G)[i];
+	if (ND_pinned(np) > P_SET)
+	    continue;
+	for (m = 0.0, k = 0; k < Ndim; k++)
+	    m += GD_sum_t(G)[i][k] * GD_sum_t(G)[i][k];
+	/* could set the color=energy of the node here */
+	if (m > max) {
+	    choice = np;
+	    max = m;
+	}
+    }
+    if (max < Epsilon2)
+	choice = NULL;
+    else {
+	if (Verbose && cnt % 100 == 0) {
+	    fprintf(stderr, "%.3f ", sqrt(max));
+	    if (cnt % 1000 == 0)
+		fprintf(stderr, "\n");
+	}
+    }
+    return choice;
+}
+
+void move_node(graph_t * G, int nG, node_t * n)
+{
+    int i, m;
+    double b[MAXDIM] = {0};
+    double c[MAXDIM] = {0};
+
+    m = ND_id(n);
+    double *a = gv_calloc((size_t)Ndim * Ndim, sizeof(double));
+    D2E(G, nG, m, a);
+    for (i = 0; i < Ndim; i++)
+	c[i] = -GD_sum_t(G)[m][i];
+    solve(a, b, c, Ndim);
+    for (i = 0; i < Ndim; i++) {
+	b[i] = (Damping + 2 * (1 - Damping) * drand48()) * b[i];
+	ND_pos(n)[i] += b[i];
+    }
+    GD_move(G)++;
+    update_arrays(G, nG, m);
+    if (test_toggle()) {
+	double sum = 0;
+	for (i = 0; i < Ndim; i++) {
+	    sum += fabs(b[i]);
+	}			/* Why not squared? */
+	sum = sqrt(sum);
+	fprintf(stderr, "%s %.3f\n", agnameof(n), sum);
+    }
+    free(a);
+}
+
+static node_t **Heap;
+static int Heapsize;
+static node_t *Src;
+
+static void heapup(node_t * v)
+{
+    int i, par;
+    node_t *u;
+
+    for (i = ND_heapindex(v); i > 0; i = par) {
+	par = (i - 1) / 2;
+	u = Heap[par];
+	if (ND_dist(u) <= ND_dist(v))
+	    break;
+	Heap[par] = v;
+	ND_heapindex(v) = par;
+	Heap[i] = u;
+	ND_heapindex(u) = i;
+    }
+}
+
+static void heapdown(node_t * v)
+{
+    int i, left, right, c;
+    node_t *u;
+
+    i = ND_heapindex(v);
+    while ((left = 2 * i + 1) < Heapsize) {
+	right = left + 1;
+	if ((right < Heapsize)
+	    && (ND_dist(Heap[right]) < ND_dist(Heap[left])))
+	    c = right;
+	else
+	    c = left;
+	u = Heap[c];
+	if (ND_dist(v) <= ND_dist(u))
+	    break;
+	Heap[c] = v;
+	ND_heapindex(v) = c;
+	Heap[i] = u;
+	ND_heapindex(u) = i;
+	i = c;
+    }
+}
+
+void neato_enqueue(node_t * v)
+{
+    int i;
+
+    assert(ND_heapindex(v) < 0);
+    i = Heapsize++;
+    ND_heapindex(v) = i;
+    Heap[i] = v;
+    if (i > 0)
+	heapup(v);
+}
+
+node_t *neato_dequeue(void)
+{
+    int i;
+    node_t *rv, *v;
+
+    if (Heapsize == 0)
+	return NULL;
+    rv = Heap[0];
+    i = --Heapsize;
+    v = Heap[i];
+    Heap[0] = v;
+    ND_heapindex(v) = 0;
+    if (i > 1)
+	heapdown(v);
+    ND_heapindex(rv) = -1;
+    return rv;
+}
+
+void shortest_path(graph_t * G, int nG)
+{
+    node_t *v;
+
+    Heap = gv_calloc(nG + 1, sizeof(node_t*));
+    if (Verbose) {
+	fprintf(stderr, "Calculating shortest paths: ");
+	start_timer();
+    }
+    for (v = agfstnode(G); v; v = agnxtnode(G, v))
+	s1(G, v);
+    if (Verbose) {
+	fprintf(stderr, "%.2f sec\n", elapsed_sec());
+    }
+    free(Heap);
+}
+
+void s1(graph_t * G, node_t * node)
+{
+    node_t *v, *u;
+    edge_t *e;
+    int t;
+    double f;
+
+    for (t = 0; (v = GD_neato_nlist(G)[t]); t++)
+	ND_dist(v) = Initial_dist;
+    Src = node;
+    ND_dist(Src) = 0;
+    ND_hops(Src) = 0;
+    neato_enqueue(Src);
+
+    while ((v = neato_dequeue())) {
+	if (v != Src)
+	    make_spring(G, Src, v, ND_dist(v));
+	for (e = agfstedge(G, v); e; e = agnxtedge(G, e, v)) {
+	    if ((u = agtail(e)) == v)
+		u = aghead(e);
+	    f = ND_dist(v) + ED_dist(e);
+	    if (ND_dist(u) > f) {
+		ND_dist(u) = f;
+		if (ND_heapindex(u) >= 0)
+		    heapup(u);
+		else {
+		    ND_hops(u) = ND_hops(v) + 1;
+		    neato_enqueue(u);
+		}
+	    }
+	}
+    }
+}
+
+void make_spring(graph_t * G, node_t * u, node_t * v, double f)
+{
+    int i, j;
+
+    i = ND_id(u);
+    j = ND_id(v);
+    GD_dist(G)[i][j] = GD_dist(G)[j][i] = f;
+}

